import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
def pkgs(data):
    d = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                d[(name, pkg['id'])] = pkg['resolvedVersion']
    return d
bp, ap = pkgs(b), pkgs(a)
if bp == ap:
    print('✅ Package versions identical — conversion is version-neutral')
else:
    for k in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv, av = bp.get(k,'MISSING'), ap.get(k,'MISSING')
        if bv != av:
            print(f'⚠️  {k[0]} / {k[1]}: {bv} → {av}')
"

